sql:
SELECT classification_id
FROM classifications
ORDER BY classification_id;

external_knowledge:
- 'Most recently accessed' refers to the latest successful access based on the access date; 
- 'good classification' means the shape has been classified as 'good' by a user and has been reviewed; 
- 'valid metrics' means the metrics have not been corrupted.

sql:
SELECT shape_name
FROM shapes
WHERE shape_id IN (
  SELECT shape_id
  FROM shape_classifications
);
